package com.quizverse.app.data.prepopulate.questions

import com.quizverse.app.data.database.entities.Question

fun techQuestionsExpert(): List<Question> = listOf(
    Question(categoryId = 7, questionText = "Welcher Zustand im MESI-Protokoll erlaubt einer Cache-Line, modifiziert zu werden, ohne dass andere Caches eine Kopie besitzen?", answerA = "Shared", answerB = "Exclusive", answerC = "Invalid", answerD = "Modified", correctAnswer = 3, explanation = "Im MESI-Protokoll ist 'Modified' der einzige Zustand, in dem eine Cache-Line veraendert wurde und die einzige gueltige Kopie im gesamten System darstellt. Der Speicher ist zu diesem Zeitpunkt veraltet (stale).", difficulty = 4, funFact = "Das MESI-Protokoll wurde 1984 von Mark Hill entwickelt. Der Uebergang von 'Modified' zu 'Invalid' erzwingt einen Write-Back in den Hauptspeicher, was als Snoop-Antwort signalisiert wird."),
    Question(categoryId = 7, questionText = "Was ist der wesentliche Unterschied zwischen dem MOESI- und dem MESI-Protokoll zur Cache-Kohaerenzkontrolle?", answerA = "MOESI unterstuetzt keine Multiprozessor-Systeme", answerB = "MOESI verwendet Token-basiertes Coherence statt Snooping", answerC = "MOESI verwendet einen zusaetzlichen 'Owned'-Zustand um Write-Backs beim Uebergang in 'Shared' zu vermeiden", answerD = "MOESI erlaubt keine 'Invalid'-Uebergaenge", correctAnswer = 2, explanation = "Der 'Owned'-Zustand in MOESI erlaubt es, eine modifizierte Cache-Line an andere Caches weiterzugeben, ohne sie zunaechst in den Hauptspeicher zurueckzuschreiben. Der Besitzer bleibt fuer den spaetere Write-Back verantwortlich.", difficulty = 4, funFact = "AMD nutzt MOESI in seinen Prozessoren seit dem Athlon 64. Ohne den 'Owned'-Zustand muesste bei jedem Shared-Uebergang ein teuerer Write-Back in den Hauptspeicher stattfinden."),
    Question(categoryId = 7, questionText = "Wie funktioniert Out-of-Order Execution (OoOE) in modernen Hochleistungs-CPUs auf Mikroarchitekturebene?", answerA = "Die CPU fuehrt Befehle strikt in Programmreihenfolge aus, aber auf mehreren parallelen Pipelines", answerB = "Ein Reorder Buffer (ROB) puffert Ergebnisse und gibt sie in korrekter Programmreihenfolge frei, waehrend der Scheduler unabhaengige Befehle vorzieht", answerC = "Die CPU sortiert den Maschinencode vor der Ausfuehrung neu", answerD = "OoOE ist nur fuer Sprungbefehle relevant und betrifft arithmetische Operationen nicht", correctAnswer = 1, explanation = "Der ROB (Reorder Buffer) ist das Herzstueck von OoOE. Befehle werden in einen reservierten Eintrag im ROB eingetragen, koennen aber ausser der Reihe ausgefuehrt werden. Erst am Retire-Punkt werden Ergebnisse in korrekter Reihenfolge in Architektur-Register uebertragen.", difficulty = 4, funFact = "Moderne CPUs wie der AMD Zen 5 haben einen ROB mit ueber 320 Eintraegen. Je groesser das ROB-Fenster, desto mehr Parallelismus kann die CPU aus sequentiellem Code extrahieren."),
    Question(categoryId = 7, questionText = "Was beschreibt der Begriff 'Branch Misprediction Penalty' und warum betraegt er bei modernen Superscalar-CPUs oft 15-20 Taktzyklen?", answerA = "Die Strafe entsteht durch den Aufbau neuer Sprungziel-Tabellen nach jedem Kontextwechsel", answerB = "Falsch vorhergesagte Spruenge verursachen L1-Cache-Misses die 15-20 Zyklen kosten", answerC = "Bei falscher Sprungvorhersage muss die Pipeline bis zum Decode-Stage gespuelt werden, was der Pipelinetiefe in Stufen entspricht", answerD = "Der Penalty entsteht durch den Interrupt-Handler der Sprungfehler korrigiert", correctAnswer = 2, explanation = "Moderne CPUs haben Pipelines mit 15-20+ Stufen (Intel Golden Cove: ~19 Stufen). Bei einer Fehlvorhersage werden alle spekulativ ausgefuehrten Befehle nach dem Sprung verworfen und die Pipeline neu befuellt. Der Penalty entspricht der Anzahl der Stufen vom Branch bis zum Commit.", difficulty = 4, funFact = "Bei einem typischen Serverprogramm mit 1% Fehlvorhersagerate und 20-Zyklus-Penalty verliert die CPU effektiv 0,2 Zyklen pro Befehl — bei 4 GHz entspricht das Hunderten von MIPS."),
    Question(categoryId = 7, questionText = "Welche Phasen durchlaeuft ein Befehl im Tomasulo-Algorithmus fuer dynamisches Instruction Scheduling?", answerA = "Fetch → Decode → Execute → Write-Back", answerB = "Fetch → Rename → Dispatch → Schedule → Execute → Retire", answerC = "Decode → Register-Read → ALU → Memory → Write-Back", answerD = "Issue → Execute → Write Result (Common Data Bus)", correctAnswer = 3, explanation = "Der Tomasulo-Algorithmus (IBM 1967) nutzt Reservierungsstationen (RS). In der 'Issue'-Phase wird ein Befehl in eine RS eingetragen und Register-Umbenennung verhindert WAW/WAR-Hazards. Nach 'Execute' werden Ergebnisse ueber den Common Data Bus (CDB) an alle wartenden RS-Eintraege gesendet.", difficulty = 4, funFact = "Robert Tomasulo entwickelte den Algorithmus fuer die IBM System/360 Modell 91 Fliesskomma-Einheit (1967). Alle modernen Out-of-Order-CPUs basieren auf diesem Prinzip, das er fuer 3.600 Dollar entwickelte."),
    Question(categoryId = 7, questionText = "Was ist 'Register Renaming' in modernen CPUs und welche Datenabhaengigkeiten eliminiert es?", answerA = "Register Renaming mappt virtuelle Speicheradressen auf physische und eliminiert Cache-Misses", answerB = "Register Renaming komprimiert Registerwerte um den Registersatz zu verkleinern", answerC = "Register Renaming weist SIMD-Registern groessere physische Adressen zu", answerD = "Register Renaming ordnet physische Register logischen Registern zu und eliminiert WAW (Write-After-Write) und WAR (Write-After-Read) Scheinabhaengigkeiten", correctAnswer = 3, explanation = "WAW und WAR sind 'falsche Abhaengigkeiten' die nur durch Wiederverwendung von Architektur-Registern entstehen. Physische Register-Umbenennungstabellen (RAT) mappen jeden Schreibvorgang auf ein neues physisches Register und beseitigen diese Hazards. Echte RAW-Abhaengigkeiten bleiben.", difficulty = 4, funFact = "x86-64 hat nur 16 Architektur-Integerregister, aber moderner CPUs wie Intel Raptor Lake haben 280+ physische Integer-Register im Backend-Registersatz."),
    Question(categoryId = 7, questionText = "Welches Sicherheitsproblem entsteht durch Speculative Execution und wie nutzt Spectre dieses aus?", answerA = "Spekulativ ausgefuehrte Befehle hinterlassen Spuren im Mikro-Architektur-Zustand (z.B. Cache), die per Timing-Seitenkanal ausgelesen werden koennen", answerB = "Spectre nutzt Pufferueberlaeufe in spekulativen Lade-Einheiten um Kernelcode auszufuehren", answerC = "Speculative Execution verursacht Race Conditions in Multi-Thread-Programmen", answerD = "Spectre manipuliert den Branch Predictor um fehlerhafte Sprungziele zu erzwingen", correctAnswer = 0, explanation = "Spectre (Variante 1) trainiert den Branch-Predictor auf eine falsche Vorhersage. Der spekulativ ausgefuehrte Code greift auf verbotene Speicherbereiche zu und bringt deren Daten in den Cache. Da der Zugriff spekulativ war, wird er rueckgaengig gemacht — aber der Cache-Zustand bleibt. Durch Flush+Reload-Timing kann der Angreifer den Inhalt ableiten.", difficulty = 4, funFact = "Spectre Variante 1 (CVE-2017-5753) betrifft praktisch alle modernen Out-of-Order-CPUs. Eine vollstaendige Hardware-Abhilfe erfordert den Verzicht auf spekulative Ausfuehrung — was die Leistung um 30-50% reduzieren wuerde."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen einem 2-Bit-Saettigungszaehler-Praediktor und einem TAGE-Branch-Predictor?", answerA = "2-Bit-Zaehler verwenden globale Geschichte, TAGE verwendet lokale Geschichte", answerB = "TAGE (TAgged GEometric history length) verwendet mehrere Praediktor-Tabellen mit geometrisch wachsenden Geschichte-Laengen und Tags zur Vermeidung von Aliasing", answerC = "2-Bit-Praediktoren haben hoehere Genauigkeit als TAGE bei direkten Spruengen", answerD = "TAGE wird ausschliesslich fuer indirekte Spruenge eingesetzt", correctAnswer = 1, explanation = "TAGE kombiniert einen Basis-Praediktor mit T Tagged-Tabellen, wobei Tabelle i eine Geschichte-Laenge von alpha^i Bits verwendet (geometrische Folge). Bei Treffer in der laengsten Tabelle wird deren Vorhersage bevorzugt. Dies reduziert Aliasing drastisch gegenueber einfachen globalen Geschichte-Praediktoren.", difficulty = 4, funFact = "TAGE erreicht Vorhersagegenauigkeiten von 98-99% bei SPEC-Benchmarks. Es ist der Sieger mehrerer Branch-Prediction-Wettbewerbe und wird von Intel, AMD und ARM in aktuellen Designs eingesetzt."),
    Question(categoryId = 7, questionText = "Was ist ein Reorder Buffer (ROB) und wie gross sind typische ROBs in aktuellen High-Performance-Prozessoren?", answerA = "Der ROB ist ein kleiner FIFO-Puffer mit 16-32 Eintraegen fuer Interrupts", answerB = "Der ROB ist eine zirkulaere Queue die alle in-flight Befehle verfolgt, um Out-of-Order Ausfuehrung mit In-Order Commit zu verbinden; moderne Designs haben 320-600+ Eintraege", answerC = "Der ROB ist ein Cache fuer haeufig ausgefuehrte Codesequenzen mit bis zu 512 KB", answerD = "Der ROB ersetzt den L1-Instruction-Cache in superscalaren Prozessoren", correctAnswer = 1, explanation = "Der ROB erlaubt einer CPU, viele Befehle gleichzeitig in unterschiedlichen Ausfuehrungs-Stadien zu halten (in-flight), aber immer in Programmreihenfolge zu committen. AMD Zen 4 hat einen ROB von 320 Eintraegen, Intel Meteor Lake ca. 512 Eintraege.", difficulty = 4, funFact = "Ein groesserer ROB ermoeglicht es der CPU, ueber Speicher-Latenzzeiten (z.B. LLC-Miss: 200+ Zyklen) hinweg produktiv zu bleiben, indem unabhaengige Befehle weiter ausgefuehrt werden."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen einer N-Way-Set-Associative Cache und einem Fully-Associative Cache hinsichtlich Hardware-Komplexitaet?", answerA = "Fully Associative hat weniger Hardware-Overhead als N-Way, da keine Indexberechnung noetig ist", answerB = "Fully Associative benoetigt einen parallelen Vergleich (CAM) fuer alle Cache-Lines gleichzeitig, was bei grosser Kapazitaet quadratische Hardware-Komplexitaet und hohe Leistungsaufnahme erzeugt", answerC = "N-Way erfordert mehr Comparator-Hardware als Fully Associative", answerD = "Es gibt keinen Hardware-Unterschied, nur einen Algorithmus-Unterschied beim Ersetzen", correctAnswer = 1, explanation = "Fully Associative Cache benoetigt einen Content-Addressable Memory (CAM) der alle Tags simultan vergleicht. Fuer eine 1-MB-Cache mit 64-Byte-Lines waeren das 16.384 parallele Comparatoren. Dies ist nur fuer kleine Strukturen wie TLBs (32-64 Eintraege) praktikabel.", difficulty = 4, funFact = "Der L1-TLB in modernen CPUs ist tatsaechlich fully associative (z.B. 64 Eintraege bei Intel), waehrend L1-Daten-Caches typischerweise 8-Way bis 16-Way Associative sind."),
    Question(categoryId = 7, questionText = "Welches FinFET-Merkmal macht diese Transistorarchitektur gegenueber planaren MOSFETs bei sub-20-nm-Prozessen ueberlegen?", answerA = "FinFETs haben eine hoehere Dotierungskonzentration im Kanal", answerB = "Das Gate umschliesst den Fin-Kanal auf drei Seiten, was deutlich bessere elektrostatische Kontrolle bietet und Short-Channel-Effekte wie DIBL stark reduziert", answerC = "FinFETs verwenden High-k-Gate-Dielektrika erst ab 5-nm-Prozessen", answerD = "FinFETs haben einen dickeren Gate-Oxid als Planar-FETs", correctAnswer = 1, explanation = "Bei sehr kurzen Kanalaengen (< 20 nm) verliert ein planares Gate die Kontrolle ueber den Kanal (DIBL: Drain-Induced Barrier Lowering). Der FinFET-Fin ist schmal genug, dass das Gate vollstaendige elektrostatische Kontrolle behaelt und Leckstrom drastisch reduziert.", difficulty = 4, funFact = "Intel patentierte den FinFET-Transistor 1999 (Hu et al., UC Berkeley). Der erste kommerzielle FinFET-Prozessor war der Intel Ivy Bridge (22 nm, 2012)."),
    Question(categoryId = 7, questionText = "Was sind die grundlegenden Unterschiede zwischen Gate-All-Around (GAA) FETs und FinFETs und warum wird GAA ab 3 nm benoetigt?", answerA = "GAA-FETs verwenden Germanium-Kanaele statt Silizium", answerB = "GAA umschliesst den Kanal auf allen vier Seiten mit dem Gate-Dielektrikum, was bei sub-5-nm-Fins noetig ist, da FinFET-Fins zu schmal fuer ausreichende Antriebsstromstaerke werden", answerC = "GAA-FETs ersetzen den MOSFET-Aufbau durch Bipolar-Transistoren", answerD = "GAA verwendet keine High-k-Materialien und ist daher einfacher herzustellen", correctAnswer = 1, explanation = "Bei sub-5-nm-Fins erreichen FinFETs physikalische Grenzen: sehr schmale Fins haben hohen Kanalwiderstand. GAA-Nanosheet-Transistoren (mehrere horizontale Si-Schichten vollstaendig vom Gate umgeben) ermoeglichen groessere effektive Kanalbreite bei gleichzeitig vollstaendiger elektrostatischer Kontrolle.", difficulty = 4, funFact = "Samsung fuehrte GAA (Nanosheet) als erstes in einem kommerziellen Produkt ein (3GAE-Prozess, 2022). TSMCs N2-Prozess (2025) wechselt ebenfalls auf GAA."),
    Question(categoryId = 7, questionText = "Was ist Extreme Ultraviolet Lithography (EUV) und bei welcher Wellenlaenge arbeitet sie?", answerA = "EUV ist eine Laser-Direktschreib-Methode bei 248 nm fuer Strukturgroessen unter 7 nm", answerB = "EUV ist ein Elektronenstrahllithografie-Verfahren bei unter 1 nm Wellenlaenge", answerC = "EUV verwendet Roentgenstrahlung bei 0,1 nm zur Sub-1-nm-Strukturierung", answerD = "EUV nutzt Plasma-erzeugte elektromagnetische Strahlung bei 13,5 nm Wellenlaenge zur Belichtung von Wafern mit reflektiven Masken in Vakuum", correctAnswer = 3, explanation = "EUV bei 13,5 nm ersetzt DUV ArF-Excimer-Laser (193 nm). Da EUV von Luft absorbiert wird, muss das gesamte optische System im Hochvakuum betrieben werden. Statt lichtbrechender Linsen werden reflektive Molybdaen-Silizium-Spiegel verwendet.", difficulty = 4, funFact = "ASML ist weltweit der einzige Hersteller von EUV-Lithografiemaschinen. Eine einzige ASML NXE-3600D kostet ca. 180 Millionen US-Dollar und wird per Frachtflugzeug in 40+ Holzkisten geliefert."),
    Question(categoryId = 7, questionText = "Was ist High-NA EUV-Lithografie und welchen Vorteil bietet die erhoehte Numerische Apertur?", answerA = "High-NA EUV arbeitet bei 6,75 nm Wellenlaenge statt 13,5 nm", answerB = "High-NA EUV erhoetzt die Numerische Apertur von 0,33 auf 0,55, was die theoretische Aufloesung auf ca. 8 nm CD verringert und Sub-2-nm-Transistoren ermoeglichen soll", answerC = "High-NA EUV nutzt zwei ueberlagerte EUV-Strahlquellen fuer doppelte Leistung", answerD = "High-NA EUV erhoetzt den Wafer-Durchsatz durch groessere Belichtungsfelder", correctAnswer = 1, explanation = "Das Rayleigh-Kriterium besagt: Aufloesung = k1 * lambda / NA. Durch Erhoehung der NA von 0,33 auf 0,55 (bei gleicher Wellenlaenge 13,5 nm) verbessert sich die Aufloesung um ~40%. ASML lieferte 2024 erste High-NA EUV (TWINSCAN EXE:5000) an Intel fuer den 14A-Prozess.", difficulty = 4, funFact = "Der High-NA EUV-Scanner ist ca. 12 Meter lang, 8 Meter hoch und wiegt ueber 200 Tonnen. Die Anamorphotischen Optiken haben eine Toleranz von weniger als 50 Pikometern."),
    Question(categoryId = 7, questionText = "Was ist der DRAM-Timing-Parameter tRCD und wie beeinflusst er die effektive Speicher-Latenz?", answerA = "tRCD ist die Zeit vom DRAM-Befehlsempfang bis zum Datenausgang (komplette Zugriffslatenz)", answerB = "tRCD ist die Refresh-Periode in Millisekunden", answerC = "tRCD (RAS-to-CAS Delay) ist die Verzoegerung zwischen Aktivieren einer Zeile (RAS) und Auslesen einer Spalte (CAS), direkt Teil der Gesamtlatenz bei jedem neuen Row-Zugriff", answerD = "tRCD beschreibt die Zeitkonstante des DRAM-Kondensators", correctAnswer = 2, explanation = "Ein DRAM-Zugriff auf eine neue Zeile erfordert: tRCD (RAS-to-CAS) + CL (CAS-Latency) + tRP (Precharge) Zyklen. tRCD repraesentiert die Zeit die benoetigt wird, die selektierte Zeile (Wortleitung) vollstaendig zu aktivieren, bevor Spalten gelesen werden koennen.", difficulty = 4, funFact = "Bei DDR5-6400 betraegt ein Taktzyklus ca. 312 Picosekunden. Typische tRCD-Werte von 36-40 Zyklen bedeuten 11-12,5 Nanosekunden Wartezeit nur fuer die Row-Aktivierung."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen DDR4 und DDR5 hinsichtlich der internen Bankenarchitektur und Command-Rate?", answerA = "DDR5 erhoetzt die Taktfrequenz auf 6400 MT/s und hat ansonsten dieselbe Architektur wie DDR4", answerB = "DDR5 splittet jeden Kanal in zwei Sub-Channels (32-Bit statt 64-Bit) und fuehrt 'Bank Groups' mit feinerer Granularitaet ein, was die effektive Bandbreite bei vielen kleinen Zugriffen verbessert", answerC = "DDR5 vergroessert die Zeilenpuffer (Row Buffer) auf 2 kB pro Bank", answerD = "DDR5 eliminiert das Refresh-Konzept durch On-Die Error-Correction", correctAnswer = 1, explanation = "DDR5 teilt den physischen 64-Bit-Kanal in zwei unabhaengige 32-Bit-Sub-Channels auf, die parallel und unabhaengig voneinander arbeiten. Ausserdem haben DDR5-Module einen On-Die ECC-Controller. Die Spannungsversorgung (VDD) wechselt von 1,2 V auf 1,1 V.", difficulty = 4, funFact = "DDR5 verlagert die Spannungsregelung vom Mainboard auf das Modul selbst (PMIC auf dem DIMM). Dies verbessert Spannungsstabilitaet bei hohen Taktfrequenzen, macht DDR5-Module aber teurer."),
    Question(categoryId = 7, questionText = "Was ist Rowhammer und warum ist es ein fundamentales DRAM-Sicherheitsproblem?", answerA = "Rowhammer ist ein Ueberhitzungsproblem bei sehr schnellen DRAM-Zugriffen", answerB = "Rowhammer ist ein Seitenkanal-Angriff ueber den DRAM-Bus zwischen Controller und Modul", answerC = "Rowhammer betrifft nur GDDR5-Speicher in Grafikkarten", answerD = "Wiederholtes Aktivieren (Hammern) einer DRAM-Zeile induziert elektrische Stoerfelder auf benachbarte Zeilen, was Bit-Flips in diesen Zeilen ohne direkten Speicherzugriff verursacht", correctAnswer = 3, explanation = "Durch das Hammern (tausende Male pro Refresh-Intervall aktivieren) einer DRAM-Zeile lecken durch kapazitive Kopplung Ladungen in benachbarte Zellen. Dies kann zu Bit-Flips in Nachbarzellen fuehren — ohne dass der Angreifer Lese-/Schreibrechte auf diese Zellen hat. TRR (Target Row Refresh) in DDR4 und DDR5 mitigiert dies.", difficulty = 4, funFact = "2015 demonstrierten Forscher von Google Project Zero einen Rowhammer-basierten Privilege-Escalation-Angriff auf Linux, der aus einem unprivilegierten Prozess Kernel-Rechte erlangte."),
    Question(categoryId = 7, questionText = "Was sind die grundlegenden Aufgaben eines Memory-Controllers und welche kritische Optimierungsstrategie nutzt er fuer Bank-Interleaving?", answerA = "Der Memory-Controller wandelt logische in physische Adressen um und cached Daten lokal um DRAM-Zugriffe zu vermeiden", answerB = "Der Memory-Controller plant DRAM-Befehle (ACT, PRE, RD, WR) und nutzt Bank-Interleaving um Precharge-Zeiten zu verbergen, indem aufeinanderfolgende Cache-Lines auf verschiedene Banken verteilt werden", answerC = "Der Memory-Controller komprimiert Speicherzugriffe um die Bandbreite zu maximieren", answerD = "Der Memory-Controller uebernimmt ECC-Korrekturen nur bei Server-Systemen", correctAnswer = 1, explanation = "Wenn Cache-Lines sequenziell auf verschiedene DRAM-Banken verteilt sind, kann der Controller Bank A lesen, waehrend Bank B prechargt und Bank C aktiviert wird. Dies maximiert die Bandbreite durch Ueberlappung der Precharge (tRP) und Aktivierungs- (tRCD) Zeiten.", difficulty = 4, funFact = "Die genaue Adress-Mapping-Funktion des Memory-Controllers (wie Adressbits auf Zeile, Spalte, Bank, Rank abgebildet werden) ist entscheidend fuer die DRAM-Performance und war lange proprietaeres Geheimnis der CPU-Hersteller."),
    Question(categoryId = 7, questionText = "Was ist PCIe TLP (Transaction Layer Packet) und welche Arten von TLPs gibt es im PCIe-Protokoll?", answerA = "TLPs sind physische Leitungen im PCIe-Kabel die verschiedene Signaltypen transportieren", answerB = "TLPs sind Timeouts im PCIe-Handshake-Protokoll", answerC = "TLPs sind spezielle DMA-Pakete nur fuer NVMe-Geraete", answerD = "TLPs sind die Basis-Datenpakete des PCIe-Protokolls; Haupttypen sind Memory Read/Write, I/O Read/Write, Configuration Read/Write und Message", correctAnswer = 3, explanation = "PCIe verwendet ein geschichtetes Protokoll mit Transaction Layer, Data Link Layer und Physical Layer. TLPs (Transaction Layer Packets) werden von der Hardware automatisch mit CRC (LCRC) geschuetzt und ueber den Data Link Layer mit Sequence-Nummern und ACK/NAK quittiert.", difficulty = 4, funFact = "PCIe ist grundsaetzlich ein paketorientiertes serielles Protokoll, obwohl es sich nach aussen wie ein paralleler Memory-Bus verhaelt. Die Kapselung ermoeglicht Switch-Topologien und virtualisierbare PCIe-Geraete (SR-IOV)."),
    Question(categoryId = 7, questionText = "Was ist PCIe ECRC (End-to-End CRC) und warum reicht LCRC (Link CRC) allein nicht aus?", answerA = "ECRC und LCRC sind identisch, ECRC ist nur der neuere Begriff fuer LCRC", answerB = "ECRC wird nur fuer NVMe-Geraete eingeschalten und ist optional", answerC = "LCRC bietet End-to-End-Schutz, ECRC ist nur fuer Multi-Root-Virtualisierung", answerD = "LCRC schuetzt nur den einzelnen Link zwischen zwei Endpunkten; ECRC schuetzt das TLP vom Ursprung bis zum Ziel und erkennt Datenkorrumpierung in PCIe-Switches", correctAnswer = 3, explanation = "In einer PCIe-Topologie mit Switches wird das TLP an jedem Switch-Port neu aufgebaut (Store-and-Forward). LCRC wird dabei entfernt und neu berechnet. Fehler im Switch selbst wuerden nicht erkannt. ECRC ist ein zusaetzliches CRC-Feld im TLP-Header das vom Sender berechnet und vom Empfaenger geprueft wird.", difficulty = 4, funFact = "ECRC ist in PCIe optional und muss von Sender und Empfaenger unterstuetzt werden. In Datenzentren und sicherheitskritischen Anwendungen (RAID-Controller) ist ECRC essentiell um stille Datenkorrumpierung zu verhindern."),
    Question(categoryId = 7, questionText = "Welches Flusskontrollmechanismus verhindert in PCIe, dass ein Sender mehr Daten sendet als der Empfaenger puffern kann?", answerA = "PCIe verwendet ein Token-Bucket-Verfahren mit festen Zeitintervallen", answerB = "PCIe nutzt ein Credit-basiertes Flusskontrollsystem wo Empfaenger Flow Control Credits (FCC) zuruecksenden die angeben wie viel Pufferplatz im Transaction Layer verfuegbar ist", answerC = "Flusskontrolle wird im PCIe-Physical-Layer durch differentielle Signalpegel geregelt", answerD = "PCIe-Flusskontrolle basiert auf ACK/NAK-Meldungen des Data Link Layers", correctAnswer = 1, explanation = "PCIe-Empfaenger senden periodisch Flow Control Credit Updates (DLLP: Data Link Layer Packets) zurueck. Credits werden pro TLP-Typ (Posted, Non-Posted, Completion) und pro Feld (Header, Data) separat vergeben. Ohne ausreichende Credits darf der Sender keine TLPs senden.", difficulty = 4, funFact = "Das Credit-System in PCIe ist so ausgelegt, dass bei vollem Puffer keine Daten verlorengehen koennen. Dies ermoeglicht das 'write-and-forget'-Modell bei Posted Writes (keine Empfangsbestaetigung noetig)."),
    Question(categoryId = 7, questionText = "Was ist Lane Margining in PCIe 4.0/5.0 und warum ist es fuer das Debugging entscheidend?", answerA = "Lane Margining misst die verfuegbare Spannungstoleranz (Voltage Margin) und Zeittoleranz (Timing Margin) einer PCIe-Lane ohne den Betrieb zu unterbrechen", answerB = "Lane Margining ist ein Kalibrierungsverfahren fuer PCIe-Kabel unter 1 Meter Laenge", answerC = "Lane Margining schaltet schwache Lanes automatisch ab und verteilt die Bandbreite auf verbleibende Lanes", answerD = "Lane Margining ist nur fuer PCIe-Switches relevant und wird in Endgeraeten nicht implementiert", correctAnswer = 0, explanation = "Lane Margining (per PCIe-Spezifikation 4.0+) erlaubt es, synthetischen Jitter und Spannungsoffsets in eine Lane einzuspeisen und dabei die Bit-Fehlerrate zu messen. So kann die Signal-Integritaets-Reserve (Margin) quantifiziert werden, ohne Downtime.", difficulty = 4, funFact = "In Rechenzentren werden PCIe-Links mit weniger als 2 dB Voltage Margin oder weniger als 30 ps Timing Margin als 'at risk' eingestuft, auch wenn sie aktuell fehlerfrei laufen."),
    Question(categoryId = 7, questionText = "Was ist Stacked Transistors-Architektur (Complementary FET / CFET) und welches Problem loest sie?", answerA = "CFETs stapeln NMOS- und PMOS-Transistoren vertikal uebereinander auf einer gemeinsamen Gate-Elektrode, was die Zellhoehe halbiert und die Flaechendichte gegenueber planaren CMOS verdoppelt", answerB = "CFETs verwenden mehrere GAA-Nanosheet-Schichten uebereinander mit gleicher Polaritaet", answerC = "CFETs stapeln mehrere identische Transistoren um den Strom zu verdoppeln", answerD = "CFETs sind eine SRAM-Optimierung bei der Lese- und Schreib-Transistoren gestapelt werden", correctAnswer = 0, explanation = "In klassischem CMOS muessen NMOS- und PMOS-Transistoren nebeneinander platziert werden (N-Well P-Well). CFET stapelt sie vertikal und teilt sich Gate-Material und Kontakte. Dies reduziert die Standardzell-Hoehe dramatisch und ist ein Schluessel fuer Post-GAA-Skalierung.", difficulty = 4, funFact = "CFET gilt als einer der naechsten grossen Schritte nach GAA in der Transistor-Roadmap. Imec und TSMC demonstrieren CFET-Prototypen seit 2023 fuer voraussichtlich 1-nm-Klasse-Prozesse nach 2027."),
    Question(categoryId = 7, questionText = "Was ist Clock Gating und Power Gating als Stromsparmechanismus in modernen SoCs?", answerA = "Clock Gating schaltet den Systemtakt bei Idle ab; Power Gating schaltet nicht benoetigte Kernspannungen ab um Leckstrom-Verluste zu eliminieren", answerB = "Clock Gating reduziert die Taktfrequenz dynamisch (DVFS), Power Gating erhoeht die Spannung bei Last", answerC = "Clock Gating und Power Gating sind identische Verfahren in unterschiedlicher Nomenklatur", answerD = "Clock Gating betrifft nur externe Schnittstellen, Power Gating nur die Recheneinheiten", correctAnswer = 0, explanation = "Clock Gating schaltet den Takt fuer inaktive Logik-Bloecke ab und eliminiert dynamische Umschalt-Verluste. Power Gating schaltet die Versorgungsspannung ganzer Domains ab (ueber Header/Footer-Transistoren) um Leckstrom (I_sub * V_dd) zu eliminieren — kritisch bei sub-5-nm-Prozessen wo Leckstrom dominiert.", difficulty = 4, funFact = "In einem modernen mobilen SoC sind zu jedem Zeitpunkt bis zu 90% der Transistoren durch Clock- oder Power-Gating inaktiv. Ohne diese Mechanismen waere der Akku eines Smartphones nach Minuten leer."),
    Question(categoryId = 7, questionText = "Was ist Dynamic Voltage and Frequency Scaling (DVFS) und wie wird der optimale Betriebspunkt bestimmt?", answerA = "DVFS passt Spannung und Frequenz statisch in der Firmware ein, um maximale Leistung bei allen Bedingungen zu garantieren", answerB = "DVFS skaliert Betriebsspannung und Taktfrequenz dynamisch proportional zur Rechenlast; der optimale Punkt minimiert P = alpha * C * V^2 * f bei gegebener Leistungsanforderung", answerC = "DVFS erhoetzt nur die Spannung bei hoher Last ohne die Frequenz anzupassen", answerD = "DVFS ist auf mehrkernige ARM-Prozessoren beschraenkt", correctAnswer = 1, explanation = "Die dynamische Leistung P = alpha * C * V^2 * f steigt quadratisch mit der Spannung. Da Spannung und Frequenz gekoppelt sind (niedrigere Frequenz erlaubt niedrigere Spannung), ist die Energieeinsparung bei Frequenzhalbierung kubisch. Ein Hardware-Performanz-Monitor (PMU) und ein OS-Scheduler bestimmen den aktuellen OPP (Operating Performance Point).", difficulty = 4, funFact = "Moderne ARM big.LITTLE und Intel P-Core/E-Core-Designs kombinieren DVFS mit heterogenem Scheduling: leichte Tasks gehen auf energieeffiziente Kerne (niedrig-V, niedrig-f), intensive Tasks auf Hochleistungskerne."),
    Question(categoryId = 7, questionText = "Was ist TSV (Through-Silicon Via) und wie ermoeglichen TSVs 3D-Chip-Stacking?", answerA = "TSVs sind leitende Durchkontaktierungen durch den Silizium-Wafer, die bei 3D-gestapelten Dies vertikale elektrische Verbindungen mit extrem kurzer Signallaufzeit und hoher Bandbreite ermoglichen", answerB = "TSVs sind vertikale Isolationsgraeben in Silizium die NMOS von PMOS trennen", answerC = "TSVs sind leitende Vias in der Metal-Interconnect-Schicht eines einzelnen Dies", answerD = "TSVs sind ein Protokoll zur Serialisierung von Daten zwischen gestapelten Dies", correctAnswer = 0, explanation = "TSVs werden durch den Silizium-Bulk gebohrt (nach dem Transistor-Prozess) und mit Kupfer gefuellt. Sie ermoeglicht vertikale Verbindungen mit 1-10 Mikrometer Durchmesser — im Vergleich zu Millimeter-langen Wire-Bonds oder PCB-Traces. HBM-Speicher (High Bandwidth Memory) verwendet TSVs fuer 1 TB/s+ Bandbreite.", difficulty = 4, funFact = "In einem HBM3e-Stapel verbinden TSVs mehrere DRAM-Dies uebereinander. Der Stapel hat typischerweise 16 Dies und ist auf einem interposer nahe der GPU montiert — der gesamte Speicher ist kleiner als eine Briefmarke."),
    Question(categoryId = 7, questionText = "Was ist ein Chiplet-Design und welche Standards (UCIe) ermoeglichen die Interoperabilitaet?", answerA = "Chiplet-Design bezeichnet monolithische Dies die in mehrere IP-Bloecke unterteilt werden", answerB = "Chiplets sind separat gefertigte Die-Einheiten verschiedener Prozesse, die ueber standardisierte Interconnects (UCIe, BoW) auf einem gemeinsamen Traeger kombiniert werden", answerC = "Chiplet ist ein Marketingbegriff fuer multi-core CPUs auf einem gemeinsamen Substrat", answerD = "Chiplets sind identische RAM-Kacheln die horizontal nebeneinander auf einem Interposer platziert werden", correctAnswer = 1, explanation = "UCIe (Universal Chiplet Interconnect Express, 2022) definiert Physical Layer, Protocol Layer und Software-Stack fuer Chiplet-zu-Chiplet-Verbindungen. Dies erlaubt es, z.B. I/O-Chiplets in 12 nm mit Rechen-Chiplets in 3 nm zu kombinieren — jeder Chiplet wird im optimalen Prozess fuer seine Funktion gefertigt.", difficulty = 4, funFact = "AMDs EPYC-Prozessoren sind seit 2017 Chiplet-basiert: mehrere Zen-CCD-Chiplets (compute) werden ueber Infinity Fabric mit einem zentralen IOD-Chiplet (I/O, Memory Controller) verbunden."),
    Question(categoryId = 7, questionText = "Was ist die Bedeutung des Begriffs 'Design Rule Check' (DRC) im VLSI-Designprozess?", answerA = "DRC ist ein Software-Tool das logische Fehler im RTL-Code des Chip-Designs findet", answerB = "DRC verifiziert, dass alle geometrischen Abstaende, Breiten und Ueberlappungen in den Masken-Layern die Mindestanforderungen des Fertigungsprozesses einhalten", answerC = "DRC ist ein Timing-Analyse-Werkzeug das Setup- und Hold-Time-Verletzungen erkennt", answerD = "DRC ueberprueft die Korrespondenz zwischen Schaltplan und Layout (Netlisten-Vergleich)", correctAnswer = 1, explanation = "Jeder Fertigungsprozess hat Tausende von DRC-Regeln: Mindestbreite und -abstand fuer jede Metal-Schicht, Mindest-Enclosure von Vias, Antennen-Regeln usw. EDA-Tools wie Mentor Calibre oder Synopsys IC Validator pruefen Milliarden von Geometrien automatisch.", difficulty = 4, funFact = "Moderne 3-nm-Prozesse haben Design-Rule-Dokumente mit ueber 10.000 Regeln. Ein typischer High-End-SoC hat nach DRC-Pruefung keine Violations bevor er zur Fab geht — auch wenn das Layout-Debugging Monate dauern kann."),
    Question(categoryId = 7, questionText = "Was ist Layout-Versus-Schematic (LVS) in der VLSI-Verifikation und welches Problem loest es?", answerA = "LVS vergleicht die Netlist die aus dem physischen Layout extrahiert wurde mit der urspruenglichen Schaltplan-Netlist und meldet Diskrepanzen wie fehlende Verbindungen oder falsche Transistorgroessen", answerB = "LVS ist eine statische Timing-Analyse die Layout-bedingte Verzoegerungen mit dem Timing-Constraint-Dokument vergleicht", answerC = "LVS prueft ob das Layout die Designregeln des Fertigungsprozesses einhalt (identisch mit DRC)", answerD = "LVS verifiziert die logische Funktionalitaet durch Simulation des extrahierten Netlists", correctAnswer = 0, explanation = "Nach dem Physical-Place-and-Route kann das Layout unbeabsichtigt von der Schaltplan-Beschreibung abweichen: fehlende Vias, falsche Transistor-Finger-Anzahl, kurzgeschlossene Netze. LVS extrahiert die Topologie aus dem GDSII-Layout und vergleicht sie mit der RTL-Netlist.", difficulty = 4, funFact = "Ein LVS-Run auf einem modernen SoC-Layout kann viele Stunden dauern und terabytes an Daten verarbeiten. Fehler die erst bei LVS gefunden werden koennen eine Redesign-Iteration erfordern die Millionen Dollar kostet."),
    Question(categoryId = 7, questionText = "Was ist Static Timing Analysis (STA) und welche Pfade werden als 'kritisch' bezeichnet?", answerA = "STA simuliert das Zeitverhalten eines Designs durch zufaellige Monte-Carlo-Simulation unter verschiedenen Prozessecken", answerB = "STA berechnet mathematisch alle moeglichen Signal-Laufzeit-Pfade in einem synchronen Design und identifiziert kritische Pfade als diejenigen mit der geringsten Setup-Timing-Marge", answerC = "STA ist eine Methode zur Messung des Laufzeitverhaltens auf Silizium durch Test-Patterns", answerD = "STA analysiert den Stromverbrauch entlang kritischer Taktpfade", correctAnswer = 1, explanation = "STA propagiert Worst-Case- und Best-Case-Laufzeiten (aus Prozess-Libraries) durch alle kombinatorischen Pfade zwischen Flip-Flops. Pfade deren Laufzeit die Taktperiode minus Setup-Zeit ueberschreiten verletzen die Setup-Constraint. Diese 'kritischen Pfade' limitieren die maximal erreichbare Taktfrequenz.", difficulty = 4, funFact = "EDA-Werkzeuge wie Synopsys PrimeTime koennen Milliarden von Timing-Pfaden in Stunden analysieren. 'Signoff-STA' unter allen PVT-Ecken (Process, Voltage, Temperature) ist Pflicht vor jedem Tapeout."),
    Question(categoryId = 7, questionText = "Was ist Electromigration (EM) und warum wird sie bei sub-10-nm-Metallinterconnects kritisch?", answerA = "Electromigration ist die physikalische Migration von Metallatomen durch Elektronenstoss-Impuls in stromdurchflossenen Leitern, was zu Luecken (opens) oder Huegeln (hillock shorts) fuehrt", answerB = "Electromigration beschreibt den kapazitiven Ladungsaustausch zwischen benachbarten Metal-Leitungen (Crosstalk)", answerC = "Electromigration ist ein thermisches Oxidationsproblem in Gate-Dielektrika unter hoher Feldstaerke", answerD = "Electromigration beschreibt das Driften von Dotieratomen in der Silizium-Kanalregion", correctAnswer = 0, explanation = "Bei sehr duennen Kupfer-Leitungen (< 10 nm Breite) wird die Stromdichte extrem hoch. Elektronen ubertragen Impuls auf Cu-Atome und treiben diese Leitungsrichtung. Nach EM-Lebensdauer-Modell (Black's Equation: MTF ~ j^(-n) * exp(Ea/kT)) begrenzt EM die maximale Stromdichte in Metal-Leitungen.", difficulty = 4, funFact = "EM-Vorhersagen erfordern komplexe Thermodynamik-Simulationen pro Metal-Segment. Ein moderner Chip hat Hunderte von Milliarden Metal-Segmente; die EM-Verifikation ist ein massiv paralleles HPC-Problem."),
    Question(categoryId = 7, questionText = "Was ist CMP (Chemical Mechanical Planarization) und warum ist es fuer die Multilayer-Metallisierung unverzichtbar?", answerA = "CMP ist ein nasschemisches Aetzverfahren um Silizium-Substrate zu reinigen vor dem Transistor-Prozess", answerB = "CMP erzeugt eine global planare Oberflaeche durch kombinierte chemische und mechanische Abrasion von Ueberschichtmaterial, was fuer litografische Tiefenschaerfe in oberen Metallschichten noetig ist", answerC = "CMP ist ein Analyseverfahren zur Messung der Metalldicke nach der Abscheidung", answerD = "CMP bezeichnet die Kombination aus Chlor-Plasma-Aetzen und Photolithografie", correctAnswer = 1, explanation = "Nach jeder Metallschicht entstehen topografische Hoehenunterschiede. Ohne Planarisierung haette die naechste Belichtungsschicht variierende Fokusbedingungen. CMP schleift die Oberflaeche mit einer Slurry-Suspension (Nanopartikel + Chemikalien) auf einem Polierpad mechanisch und chemisch eben.", difficulty = 4, funFact = "Ein moderner 3-nm-Chip hat 15+ Metal-Schichten. Zwischen jede Schicht kommt ein CMP-Schritt. Die Gleichfoermigkeit muss auf dem gesamten 300-mm-Wafer auf < 5 nm Dickenvarianz kontrolliert werden."),
    Question(categoryId = 7, questionText = "Welche Funktion hat ein Scoreboard in einer Out-of-Order-Superscalar-CPU und was ist der Unterschied zum Tomasulo-Algorithmus?", answerA = "Das CDC 6600-Scoreboard verfolgt den Zustand jedes Functional-Unit und jeden Register durch eine zentrale Steuertabelle ohne Register-Umbenennung; Tomasulo fuegt Register-Umbenennung durch Reservierungsstationen hinzu", answerB = "Ein Scoreboard ist eine modernere Weiterentwicklung des Tomasulo-Algorithmus mit mehr Puffern", answerC = "Scoreboard und Tomasulo sind funktional identisch aber unterscheiden sich nur im Hardware-Aufwand", answerD = "Scoreboards werden nur in VLIW-Architekturen eingesetzt, Tomasulo in superskalaren Designs", correctAnswer = 0, explanation = "Das CDC 6600 Scoreboard (1964) ist ein zentralisiertes Kontrollschema ohne Register-Umbenennung; WAW- und WAR-Hazards werden durch Stalls geloest. Tomasulo (1967) eliminiert WAW/WAR durch Register-Umbenennung in Reservierungsstationen und verteilt die Steuerlogik, was hoeheren Parallelismus erlaubt.", difficulty = 4, funFact = "Seymour Cray entwarf das CDC 6600 mit dem Scoreboard, dem ersten superskalaren Computer. Er verwendete 60-Bit-Worte und bis zu 10 gleichzeitig aktive Functional Units — revolutionaer fuer 1964."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen einem physischen und einem logischen Adressraum in einem moderner CPU mit MMU?", answerA = "Logische Adressen sind 16-Bit-Segmentoffsets in x86, physische Adressen sind 64-Bit DRAM-Adressen; beide werden direkt vom CPU-Kern verarbeitet", answerB = "Physische Adressen sind Kernel-Adressen, logische Adressen sind User-Space-Adressen; beide referenzieren denselben Speicherbereich", answerC = "Der Unterschied existiert nur bei 32-Bit-Betriebssystemen mit mehr als 4 GB RAM (PAE)", answerD = "Logische Adressen sind vom Prozess verwendete virtuelle Adressen; die MMU uebersetzt diese via Seitentabellen (TLB) in physische DRAM-Adressen, was Isolierung und Virtualisierung ermoeglicht", correctAnswer = 3, explanation = "Die MMU (Memory Management Unit) mit TLB (Translation Lookaside Buffer) ist der Hardware-Mechanismus fuer Adress-Uebersetzung. x86-64 unterstuetzt 4-Level und 5-Level-Seitentabellen (48-Bit und 57-Bit virtuelle Adressraeume). Jede TLB-Fehltreffung (Miss) erfordert einen kostspieligen Seitentabellen-Durchlauf (Page Table Walk).", difficulty = 4, funFact = "Ein TLB-Miss verursacht 10-100 DRAM-Zugriffe fuer den Page Table Walk. Bei speicherintensiven Anwendungen mit grossem Working Set kann TLB-Thrashing die Leistung um 50%+ reduzieren. Hugepages (2 MB statt 4 KB) reduzieren TLB-Druck drastisch."),
    Question(categoryId = 7, questionText = "Was ist das NUMA (Non-Uniform Memory Access) Problem in Multiprozessorsystemen und wie adressiert es der Betriebssystem-Scheduler?", answerA = "NUMA bezeichnet ungleich grosse L3-Caches in Multiprozessorsystemen", answerB = "NUMA ist ein Protokoll fuer kohaerentem Cache-Zugriff zwischen NUMA-Knoten und ersetzt MESI", answerC = "In NUMA-Systemen haben Prozessoren unterschiedlich schnellen Zugriff auf verschiedene Speicherbereiche (lokal vs. remote ueber Interconnect); der OS-Scheduler platziert Threads idealerweise nahe ihrem Speicher", answerD = "NUMA beschreibt die ungleiche Verteilung von Interrupts auf CPU-Kerne in x86-Systemen", correctAnswer = 2, explanation = "In einem 2-Sockel-System kann ein Thread auf Sockel A auf lokalen RAM mit 80 ns zugreifen, auf den RAM von Sockel B aber nur mit 160 ns (via UPI oder Infinity Fabric). NUMA-aware Scheduling (libnuma, numactl) und NUMA-aware Memory-Allokation sind fuer High-Performance-Server-Workloads kritisch.", difficulty = 4, funFact = "AMD EPYC-Prozessoren mit mehreren CCDs (Chiplets) haben sogar intra-Socket-NUMA-Effekte: RAM-Zugriff ueber den IOD zu einem anderen CCD kostet extra Latenz, was die NUMA-Topologie komplexer macht."),
    Question(categoryId = 7, questionText = "Was ist das Problem der 'false sharing' in Multicore-Cache-Systemen und wie wird es vermieden?", answerA = "False Sharing bezeichnet das irrtueml. Teilen von Datensegmenten zwischen Prozessen durch fehlerhafte Pointer-Arithmetik", answerB = "False Sharing ist ein MESI-Protokoll-Fehler bei dem Shared-State faelschlich in Invalid wechselt", answerC = "False Sharing tritt bei Non-Temporal Stores auf die den Cache umgehen", answerD = "False Sharing tritt auf wenn zwei Threads auf verschiedene Variablen in derselben Cache-Line schreiben, was Cache-Invalidierungs-Tsunamis und Leistungseinbrueche verursacht", correctAnswer = 3, explanation = "Cache-Lines sind typischerweise 64 Bytes. Wenn Thread A auf Byte 0-3 schreibt und Thread B auf Byte 32-35 (beide in derselben 64-Byte-Line), muss trotzdem die gesamte Cache-Line fuer jede Schreiboperation zwischen Cores hin- und herbewegt werden. Abhilfe: Padding auf Cache-Line-Groesse oder __cacheline_aligned.", difficulty = 4, funFact = "False Sharing kann einen 10-100x Leistungseinbruch verursachen. Das beruehm Beispiel in Linux-Kernel-Tuning: Java-Garbage-Collectors leiden haeufig unter False Sharing in Referenz-Zaehler-Arrays, weshalb Java 8 @Contended-Annotationen einfuehrte."),
    Question(categoryId = 7, questionText = "Was ist ein Store Buffer in einer modernen CPU und welche Ordnungs-Semantik wird dadurch sichtbar?", answerA = "Der Store Buffer ist identisch mit dem Write-Combining Buffer fuer Memory-Mapped-I/O", answerB = "Der Store Buffer ist ein Hardware-Prefetcher fuer sequenzielle Schreibzugriffe", answerC = "Der Store Buffer puffert Schreibvorgaenge asynchron zur Cache-Hierarchie und kann dazu fuehren, dass ein Lesevorgang desselben Threads seinen eigenen noch nicht committen Store sieht (Store-to-Load Forwarding), aber andere Threads aeltere Werte lesen", answerD = "Der Store Buffer eliminiert Write-Back-Latenz durch direktes Schreiben in den L3-Cache", correctAnswer = 2, explanation = "Store-Buffer-Einfuegung erzeugt TSO (Total Store Order) Semantik auf x86: Speicher einer CPU erscheinen anderen CPUs moeglicherweise in anderer Reihenfolge als den lokalen Lesevorgaengen des Schreibers. MFENCE/SFENCE-Befehle erzwingen Store-Buffer-Flush und sichern Ordnung.", difficulty = 4, funFact = "ARM und RISC-V haben schwaechere Speichermodelle als x86 (WMO/Relaxed Memory Order). Code der auf x86 ohne Locks laeuft kann auf ARM Data Races haben. Dies ist ein haufiger Portierungsfehler."),
    Question(categoryId = 7, questionText = "Was ist die Rolle von Interconnects wie Intel UPI (Ultra Path Interconnect) und AMD Infinity Fabric in Multi-Sockel-Systemen?", answerA = "UPI und Infinity Fabric sind PCIe-basierte Verbindungen fuer I/O-Erweiterungen zwischen Sockeln", answerB = "UPI (ehem. QPI) und Infinity Fabric sind proprietaere Cache-kohaerenzte Hochgeschwindigkeits-Interconnects fuer Prozessor-zu-Prozessor-Kommunikation mit MESI-Protokoll-Erweiterungen fuer CC-NUMA", answerC = "UPI und Infinity Fabric sind Software-Abstraktionsschichten fuer NUMA-Topologie-Management", answerD = "UPI ist ein Intel-proprietaeres Protokoll fuer interne Die-zu-Die-Verbindung innerhalb eines Sockels", correctAnswer = 1, explanation = "UPI3.0 bietet 24 GT/s pro Lane bei bis zu 4 Links. Infinity Fabric laeuft mit bis zu 2000 MHz und verbindet CCDs, IOD und Memory-Controller innerhalb eines EPYC-Prozessors sowie zwischen EPYC-Sockeln. Beide Protokolle implementieren verteilte Cache-Kohaerenz ueber NUMA-Grenzen.", difficulty = 4, funFact = "AMDs Infinity Fabric wird nicht nur zwischen Sockeln verwendet, sondern auch intern zwischen den EPYC-Chiplets (CCD-zu-IOD). Die Infinity-Fabric-Frequenz ist an die Speicherfrequenz gekoppelt (1:1 oder 1:2 Modus)."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen einem Barrel Processor und einem Simultaneous Multithreading (SMT) Prozessor?", answerA = "Barrel Processing interleaved mehrere Threads auf einer einzelnen In-Order-Pipeline (immer ein anderer Thread pro Zyklus) und vermeidet Stalls; SMT fuehrt mehrere Threads auf einer superskalaren OoO-Pipeline gleichzeitig aus", answerB = "Barrel Processing ist veraltet und SMT ist die neuere Implementierung desselben Konzepts", answerC = "SMT verdoppelt physische Pipeline-Ressourcen, Barrel Processing teilt alle Ressourcen", answerD = "Barrel Processing ist auf VLIW-Architekturen beschraenkt, SMT auf CISC-Architekturen", correctAnswer = 0, explanation = "In einem Barrel-Processor (z.B. Sun Niagara / UltraSPARC T1) hat der Prozessor z.B. 8 Thread-Kontexte und wechselt jeden Zyklus zum naechsten Thread. Stalls eines Threads sind unsichtbar. SMT (z.B. Hyper-Threading) ermoeglicht Abwechseln mehrerer Threads innerhalb derselben OoO-Maschinerie.", difficulty = 4, funFact = "Suns Niagara T1 (2005) hatte 8 Kerne mit je 4 Barrel-Threads (32 HW-Threads total) und gewann SPECweb-Benchmarks trotz niedriger Einzelthread-Leistung dank extremem Throughput."),
    Question(categoryId = 7, questionText = "Was ist das Concept von IOMMU (Input-Output Memory Management Unit) und warum ist sie fuer Virtualisierung kritisch?", answerA = "IOMMU ermoeglicht DMA-faehigen Geraeten (Netzwerk, GPU) direkte Speicherzugriffe nur in erlaubte physische Speicherbereiche und verhindert unautorisierten DMA-Zugriff; fuer PCI-Passthrough in VMs unverzichtbar", answerB = "IOMMU ist ein Cache fuer I/O-Adressen der DMA-Transfers beschleunigt", answerC = "IOMMU ist ein Prozessor-interner TLB fuer Memory-Mapped-I/O-Adressen", answerD = "IOMMU ermoeglicht NVMe-Geraeten, den L3-Cache direkt zu beschreiben (Storage-class Memory)", correctAnswer = 0, explanation = "Ohne IOMMU koennte ein DMA-faehiges Geraet in einer VM auf beliebige physische Speicherbereiche anderer VMs oder des Hypervisors zugreifen. Mit IOMMU (Intel VT-d, AMD-Vi) werden DMA-Transfers durch I/O-Seitentabellen auf erlaubte physische Bereiche beschraenkt.", difficulty = 4, funFact = "IOMMU ermoeglicht auch VFIO (Virtual Function I/O) unter Linux, das PCIe-Passthrough fuer VMs erlaubt. So kann eine GPU direkt an eine VM durchgereicht werden mit nahezu nativer Leistung."),
    Question(categoryId = 7, questionText = "Was ist die physikalische Grundlage von DRAM-Retention und warum braucht DRAM Refresh?", answerA = "DRAM-Zellen speichern Ladung in einem Kondensator (typisch 10-20 fF). Der Kondensator entlaedt sich durch Sub-Threshold-Leckstrom des Zugriffstransistors; Refresh laedt ihn alle 64 ms (Standard) oder 32 ms (hohe Temperatur) auf", answerB = "DRAM nutzt magnetische Domainorientierung zur Datenspeicherung die durch thermisches Rauschen periodisch zurueckgesetzt wird", answerC = "Refresh wird durch kapazitive Kopplung zwischen Bitleitungen verursacht die periodisch ausgeglichen werden muessen", answerD = "DRAM verliert Daten durch Elektromigration in den Bitleitungen und Refresh schreibt die Daten mechanisch neu", correctAnswer = 0, explanation = "Die Kapazitaet einer DRAM-Zelle ist extrem klein (10-20 fF). Bei einem Leckstrom von 1 fA entlaedt sich der Kondensator in ca. 10-100 ms auf die Haelfte. Der Refresh-Zyklus aktiviert jede Zeile und schreibt deren Zustand verstaerkt zurueck (Read-Amplify-Write).", difficulty = 4, funFact = "Die JEDEC-Retention-Spezifikation fuer Standard-DRAM ist 64 ms bei 85 Grad Celsius. In der Praxis haben viele Zellen deutlich laengere Retention-Zeiten — was das Rowhammer-Fenster fuer Angriffe oeffnet."),
    Question(categoryId = 7, questionText = "Was sind 'Schmetterlings-Diagramme' (Butterfly Plots / Eye Diagrams) und was messen sie bei seriellen Schnittstellen?", answerA = "Butterfly Plots visualisieren die kumulierte Signal-Amplitude aller moeglichen Bit-Kombinationen ueberlagert auf einen Taktzyklus und zeigen Timing-Jitter und Spannungsmargen auf einen Blick", answerB = "Butterfly Plots sind Frequenzspektren von seriellen Signalen zur Messung von EMV-Emissionen", answerC = "Butterfly Plots zeigen die Strom-Spannungs-Kennlinie von Terminierungswiderstaenden", answerD = "Butterfly Plots sind Impedanz-Messungen entlang der Leiterplatte", correctAnswer = 0, explanation = "Ein Eye Diagram entsteht durch Ueberlagerung vieler Bitsequenzen auf einem Taktzyklus im Oszilloskop. Die Augenhoehe (vertical eye opening) repraesentiert Spannungsmargen, die Augenbreite (horizontal eye opening) die Timing-Marge. Ein weit offenes Auge bedeutet gute Signalintegritaet.", difficulty = 4, funFact = "Fuer PCIe 5.0 mit 32 GT/s hat jede Periode nur 31,25 Picosekunden. Eye-Diagramme werden mit Hochgeschwindigkeits-Oszilloskopen (> 100 GHz Bandbreite) oder in Hardware durch eingebaute BERT-Logik aufgenommen."),
    Question(categoryId = 7, questionText = "Was ist ein PAM4-Signal (Pulse Amplitude Modulation 4) und wie unterscheidet es sich von NRZ bei hochseriellen Schnittstellen?", answerA = "PAM4 kodiert 2 Bit pro Symbol durch vier Spannungspegel (+1, +1/3, -1/3, -1) und verdoppelt so die Datenmenge pro Baud-Rate gegenueber NRZ; dies verschlechtert jedoch SNR und erfordert komplexe Equalisierung", answerB = "PAM4 ist eine Phasenmodulation die vier Quadranten des Einheitskreises nutzt, identisch mit QPSK", answerC = "PAM4 und NRZ sind bei gleicher Bitrate identisch, nur das Codierungsformat unterscheidet sich", answerD = "PAM4 wird nur in optischen Ethernet-Verbindungen eingesetzt, NRZ in elektrischen PCIe-Links", correctAnswer = 0, explanation = "NRZ (Non-Return-to-Zero) kodiert 1 Bit pro Symbol (2 Pegel: +1, -1). PAM4 nutzt 4 Spannungspegel und kodiert 2 Bit pro Symbol. Bei gleicher Symbol-Rate (Baud) wird doppelte Bitrate erreicht. Nachteile: SNR sinkt um ~9,5 dB; grosse Bit-Fehlerrate ohne Forward-Error-Correction (FEC).", difficulty = 4, funFact = "PCIe 6.0 wechselt von NRZ (PCIe 5.0) auf PAM4 und erreicht so 64 GT/s bei unveraenderter Symbol-Rate. Pflicht-FEC (RS-FEC) kompensiert die schlechtere Signal-Qualitaet."),
    Question(categoryId = 7, questionText = "Was ist PLL (Phase-Locked Loop) in einem Chip-Design und welche Rolle spielt sie in der Taktverteilung?", answerA = "Eine PLL ist ein Regelkreis aus VCO, Phasenkomparator und Loop-Filter der eine hochfrequente, phasenstabile Taktfrequenz aus einer niederfrequenten Referenz synthetisiert; sie isoliert interne Takte von externen Referenz-Jitter", answerB = "Eine PLL ist ein Protokoll zur synchronen Kommunikation zwischen Chips ohne gemeinsame Taktleitung", answerC = "Eine PLL ist ein Cache-Coherenz-Protokoll fuer verteilte Mehrkern-Prozessoren", answerD = "PLL bezeichnet den Prozess der Frequenz-Kalibrierung bei DDR-Speicher-Interfaces", correctAnswer = 0, explanation = "Die PLL generiert z.B. 4 GHz aus einer 100-MHz-Referenz (Multiplikator M=40). Der VCO (Voltage-Controlled Oscillator) wird durch den Phasenkomparator geregelt der VCO-Ausgang mit dem Referenz-Takt vergleicht. Clock-Trees verteilen das PLL-Signal mit minimalem Skew auf alle Flip-Flops.", difficulty = 4, funFact = "Moderner CPUs haben dutzende PLLs: je eine pro CPU-Kern, fuer Memory-Controller, PCIe, USB usw. Die PLL-Jitter-Spezifikation (typisch < 1 ps RMS Integrated Jitter) ist kritisch fuer hohe Taktfrequenzen und serielle Interfaces."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen synchronem SRAM (cache) und asynchronem SRAM hinsichtlich des Interface-Protokolls?", answerA = "Synchrones SRAM verwendet ein Takt-Signal und registriert Adresse, Daten und Steuersignale an Taktflanken; asynchrones SRAM antwortet direkt auf Adress-/Steuersignaele ohne Takt mit einer Zugriffszeit", answerB = "Synchrones SRAM ist langsamer als asynchrones SRAM da der Takt zusaetzliche Latenz einfuehrt", answerC = "Asynchrones SRAM erfordert Refresh-Zyklen, synchrones SRAM nicht", answerD = "Synchrones SRAM wird nur in L1-Caches eingesetzt, asynchrones SRAM in externen Chips", correctAnswer = 0, explanation = "Asynchrones SRAM hat typische Zugriffszeiten von 5-45 ns ohne Takt (z.B. 74HC-Register-basierte Designs). Synchrones SRAM (wie QDR-SRAM in Netzwerk-Switches) taktet mit 300-400 MHz und hat deterministische Latenzen: Daten erscheinen nach einer festen Anzahl von Taktzyklen.", difficulty = 4, funFact = "QDR-II+ SRAM (Quad Data Rate) wird in Hochgeschwindigkeits-Routing-Tabellen und TCAM-Assistenz-Speicher in Netzwerk-Chips eingesetzt, da es simultan lesen und schreiben kann (getrennte Read/Write-Ports)."),
    Question(categoryId = 7, questionText = "Was ist Antenna Effect (Plasma-Ionen-Schaeden) in der VLSI-Fertigung und wie wird er verhindert?", answerA = "Der Antenna-Effekt beschreibt ladungsinduzierte Gate-Oxid-Schaeden waehrend Plasma-Aetzvorgaengen: lange Metallleitungen sammeln Plasmaladung und entladen sich durch das Gate-Oxid des angeschlossenen Transistors", answerB = "Antenna Effect bezeichnet kapazitive Kopplung zwischen langen parallelen Metallleitungen", answerC = "Antenna Effect ist ein Reliability-Problem durch statische Aufladung beim Wafer-Transport", answerD = "Antenna Effect beschreibt EMV-Abstrahlung durch lange On-Chip-Metallleitungen", correctAnswer = 0, explanation = "Waehrend des RIE-Aetzens sammeln Metall-Leitungen (Antennen) Plasma-Ionen. Bei sehr grossem Verhaeltnis Leiter-Flaeche zu angeschlossener Gate-Oxid-Flaeche (Antenna Ratio) kann die Spannung das Gate-Oxid schaedigen. DRC-Antenna-Rules und das Hinzufuegen von Dioden als Ableiter (Antenna Diodes) verhindert dies.", difficulty = 4, funFact = "Antenna Rules sind Teil jeder Process-Design-Kit (PDK) DRC-Regeldatei. EDA-Tools erkennen Antenna-Violations automatisch und schlagen das Einsetzen von Antenna-Dioden (Reverse-Bias-Dioden) als Ableiter vor."),
    Question(categoryId = 7, questionText = "Was ist das Konzept von Hardware Transactional Memory (HTM) und wie unterscheidet es sich von Software-Locks?", answerA = "HTM erlaubt es, Speicherzugriffe als atomare Transaktionen auszufuehren; die CPU prueft Hardware-Konflikte und macht bei Konflikt die gesamte Transaktion rueckgaengig (Abort) ohne Locks zu verwenden", answerB = "HTM ist eine Erweiterung von Software-Transaktionalem Speicher durch Hardware-Beschleunigung der Lock-Acquisition", answerC = "HTM implementiert eine vollstaendige Datenbank-Engine in der CPU fuer Speicherzugriffe", answerD = "HTM ist ein Intel-internes Konzept nur fuer L3-Cache-Verwaltung in Xeon-Prozessoren", correctAnswer = 0, explanation = "Intel TSX (Transactional Synchronization Extensions) und IBM POWER HTM bieten Hardware-Transactional-Memory. Nicht-konfligierende Transaktionen laufen ohne jegliche Lock-Overhead durch. Nur bei Konflikten oder bestimmten Ereignissen (Interrupts, Cache-Evictions) muss ein Fallback-Pfad (z.B. klassischer Lock) ausgefuehrt werden.", difficulty = 4, funFact = "Intel deaktivierte TSX in mehreren CPU-Generationen aufgrund von Sicherheitsproblemen (TSX-Asynchronous-Abort, CVE-2019-11135). TSX-Verwendung in Produktionscode war immer kontrovers wegen der nicht-deterministischen Abort-Bedingungen."),
    Question(categoryId = 7, questionText = "Was sind die Auswirkungen von Process, Voltage und Temperature (PVT) Variationen auf die maximale Taktfrequenz eines digitalen VLSI-Chips?", answerA = "PVT-Variationen sind vernachlaessigbar da moderne EDA-Tools Worst-Case-Analyse bei allen Variationen durchfuehren", answerB = "Prozess-Variation (Schwankungen in Transistorgroesse und Dotierung), Spannungsschwankungen (VDD), und Temperaturschwankungen veraendern Transistor-Charakteristiken; STA muss unter allen PVT-Ecken signieren um korrekte Funktion zu garantieren", answerC = "PVT-Variationen beeinflussen nur die statische Verlustleistung, nicht die Timing-Signierungsbedingungen", answerD = "PVT-Analyse ist nur fuer SRAM-Zellen relevant, nicht fuer Logik-Pfade", correctAnswer = 1, explanation = "In der Ecke 'SS, 0,9V, 125C' (Slow Process, niedrige Spannung, hohe Temperatur) laufen Transistoren am langsamsten. In 'FF, 1,1V, -40C' am schnellsten. STA muss Setup-Timing unter SS/125C und Hold-Timing unter FF/-40C bestehen — die Setup-Ecke begrenzt die maximale Taktfrequenz.", difficulty = 4, funFact = "Ein Chip der bei 'Typical'-Bedingungen 4 GHz schafft, muss moeglicherweise auf 3,5 GHz abgesenkt werden, um unter Worst-Case-PVT-Bedingungen sicher zu laufen. Die Differenz ist der 'Timing-Guardband'."),
    Question(categoryId = 7, questionText = "Was ist der Unterschied zwischen SRAM-Lese- und Schreibstabilitaet und warum sind beide fuer 6T-SRAM-Zellendesign kritisch?", answerA = "Lesestabilitaet (SNM: Static Noise Margin) beschreibt Robustheit beim Lesen gegen Stoerungen; Schreibfaehigkeit (WM: Write Margin) beschreibt die Faehigkeit den Zellwert zu ueberschreiben; beide sind durch Beta-Ratio der 6T-Zelle gegenlaeuefig optimiert", answerB = "SRAM-Schreibstabilitaet ist gegenueber Lesestabilitaet vernachlaessigbar und hat keinen Einfluss auf die Zellendesign-Parameter", answerC = "Lese- und Schreibstabilitaet sind identisch in der 6T-Zelle und werden gemeinsam durch Transistorgroesse optimiert", answerD = "Lesestabilitaet betrifft nur SRAM in L1-Caches, Schreibstabilitaet nur in Register-Files", correctAnswer = 0, explanation = "In der 6T-SRAM-Zelle gibt es 3 Transistorgroessen-Verhaeltnisse: Zugriff-Transistoren (Access, A), Pull-Down-Transistoren (PD) und Pull-Up (PU). Groesseres PD/A-Verhaeltnis (Beta Ratio) verbessert Lesestabilitaet, verschlechtert aber Schreibfaehigkeit. Dies ist ein fundamentaler Design-Trade-off.", difficulty = 4, funFact = "Bei sub-20-nm-Prozessen naehern sich SRAM-Zellen physikalischen Grenzen: PVT-Variationen eines einzelnen Transistors in der 6T-Zelle koennen die ganze Zelle funktionsunfaehig machen. Dies erfordert Assist-Schaltungen (Voltage Assist) oder 8T/10T-SRAM-Zellen."),
    Question(categoryId = 7, questionText = "Was ist das Konzept von Amdahls Gesetz in Bezug auf Parallelisierungsgewinne und welche Implikation hat es fuer Chip-Multithreading?", answerA = "Amdahls Gesetz zeigt, dass der maximale Speedup durch parallele Verarbeitung durch den seriellen Anteil des Programms begrenzt ist: S_max = 1/(1-P) wobei P der parallelisierbare Anteil ist", answerB = "Amdahls Gesetz besagt, dass Prozessorleistung sich alle 18 Monate verdoppelt (identisch mit Moores Law)", answerC = "Amdahls Gesetz beschreibt den linearen Zusammenhang zwischen Kernan-zahl und Gesamt-Durchsatz bei perfekt parallelisierbaren Workloads", answerD = "Amdahls Gesetz gilt nur fuer SIMD-Parallelismus, nicht fuer Task-Parallelismus", correctAnswer = 0, explanation = "Wenn 5% eines Programms seriell sind, ist der maximale Speedup durch Parallelisierung 1/(0,05) = 20x, egal wie viele CPUs verwendet werden. Dies erklaert warum bei Servern und Supercomputern Einzelthread-Leistung fuer seriell-bottlenecked Anwendungen wichtig bleibt.", difficulty = 4, funFact = "Gustafson's Law (1988) erweiterte Amdahls Gesetz: wenn Problemgroessen mit der Prozessorzahl skalieren (Weak Scaling), kann der Speedup linear sein. Dies erklaert den Wert von Hochparallel-Hardware fuer grosse wissenschaftliche Simulationen.")
)
